182→    } else if (selectedType === 'door') {
183→      const door = floor.doors.find(d => d.id === selectedId);
184→      const wall = door ? floor.walls.find(w => w.id === door.wallId) : null;
185→      if (door) {
186→        content = <DoorProperties door={door} wall={wall} dispatch={dispatch} floorId={activeFloorId} editorDispatch={editorDispatch} />;
187→      }
188→    } else if (selectedType === 'window') {
189→      const win = floor.windows.find(w => w.id === selectedId);
