 1→import { createDoor } from '@/domain/models';
 2→import { distanceToSegment } from '@/geometry/line';
 3→import { projectPointOnWall, wallLength } from '@/geometry/wallGeometry';
 4→import { DOOR_WIDTH } from '@/domain/defaults';
 5→
 6→const WALL_DETECT_RADIUS = 500; // mm
 7→
 8→function findNearestWall(modelPos, walls) {
 9→  let best = null;
10→  let bestDist = WALL_DETECT_RADIUS;
11→
12→  for (const wall of walls) {
13→    const d = distanceToSegment(modelPos, wall.start, wall.end);
14→    if (d < bestDist) {
15→      best = wall;
16→      bestDist = d;
17→    }
18→  }
19→  return best;
20→}
21→
22→export function createDoorPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId }) {
23→  return {
24→    onMouseMove(modelPos, e, toolState) {
25→      const floor = getFloor(activeFloorId);
26→      const wall = findNearestWall(modelPos, floor.walls);
27→
28→      if (wall) {
29→        const offset = projectPointOnWall(wall, modelPos);
30→        const halfWidth = DOOR_WIDTH / 2;
31→        const maxOffset = wallLength(wall) - halfWidth;
32→        const clampedOffset = Math.max(halfWidth, Math.min(maxOffset, offset));
33→
34→        editorDispatch({
35→          type: 'UPDATE_TOOL_STATE',
36→          payload: {
37→            previewWallId: wall.id,
38→            previewOffset: clampedOffset,
39→          },
40→        });
41→      } else {
42→        editorDispatch({
43→          type: 'UPDATE_TOOL_STATE',
44→          payload: { previewWallId: null, previewOffset: null },
45→        });
46→      }
47→    },
48→
49→    onMouseDown(modelPos, e, toolState) {
50→      if (e.button !== 0) return;
51→      if (!toolState.previewWallId) return;
52→
53→      const door = createDoor(toolState.previewWallId, toolState.previewOffset);
54→      dispatch({ type: 'DOOR_ADD', floorId: activeFloorId, door });
55→    },
56→
57→    onKeyDown(e, toolState) {
58→      if (e.key === 'Escape') {
59→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
60→      }
61→    },
62→
63→    getCursor(toolState) {
64→      return toolState.previewWallId ? 'copy' : 'not-allowed';
65→    },
66→  };
67→}
